// tests/dashboard/cors-security.test.ts
describe('CORS Security', () => {
  test('应该允许开发环境本地端口', async () => {
    const response = await axios.get('http://localhost:3000/api/health', {
      headers: { Origin: 'http://localhost:5173' }
