### 📝 详细实现方案

#### 1. 创建敏感数据过滤器

```typescript
// src/utils/sensitive-data-filter.ts

interface FilterOptions {
  maskChar?: string;
  keepStart?: number;
  keepEnd?: number;
}

const SENSITIVE_PATTERNS = [
  /token/i,
  /password/i,
  /secret/i,
  /api[_-]?key/i,
  /auth/i,
  /credential/i,
];

export function sanitize(obj: any, options: FilterOptions = {}): any {
  const { maskChar = '*', keepStart = 0, keepEnd = 0 } = options;

  if (typeof obj === 'string') {
    return maskSensitiveString(obj, maskChar, keepStart, keepEnd);
  }

  if (Array.isArray(obj)) {
    return obj.map(item => sanitize(item, options));
  }

  if (obj && typeof obj === 'object') {
    const sanitized: any = {};
    for (const [key, value] of Object.entries(obj)) {
      const isSensitive = SENSITIVE_PATTERNS.some(pattern => 
        pattern.test(key)
      );

      if (isSensitive && typeof value === 'string') {
        sanitized[key] = maskValue(value, maskChar, keepStart, keepEnd);
      } else {
        sanitized[key] = sanitize(value, options);
      }
    }
    return sanitized;
  }

  return obj;
}

function maskValue(value: string, maskChar: string, keepStart: number, keepEnd: number): string {
  if (value.length <= keepStart + keepEnd) {
    return maskChar.repeat(value.length);
  }

  const start = value.slice(0, keepStart);
  const end = value.slice(-keepEnd);
  const middle = maskChar.repeat(value.length - keepStart - keepEnd);

  return `${start}${middle}${end}`;
}

function maskSensitiveString(str: string, maskChar: string, keepStart: number, keepEnd: number): string {
  // 检测是否是类似 Bearer token 的字符串
  if (/^Bearer\s+/i.test(str) || str.length > 30) {
    return maskValue(str, maskChar, keepStart, keepEnd);
  }
  return str;
}
```

